284→  const ruleId = crypto.randomUUID();
285→
286→  const rule = formatRuleSchema.parse({
287→    id: ruleId,
288→    importId: input.importId,
289→    targetFormat: input.targetFormat,
290→    kind: "render",
291→    scope: "import_local",
292→    status: "active",
293→    selector: input.selector,
294→    instruction: input.instruction,
295→    compiledRule: input.effect,
296→    sourceSessionId: input.sourceSessionId,
297→    createdAt: timestamp,
298→    updatedAt: timestamp,
299→  });
300→
301→  db.transaction((tx) => {
302→    tx.insert(formatRules)
303→      .values({
304→        id: rule.id,
305→        importId: rule.importId,
306→        targetFormat: rule.targetFormat,
307→        kind: rule.kind,
308→        scope: rule.scope,
309→        status: rule.status,
310→        selectorJson: JSON.stringify(rule.selector),
311→        instruction: rule.instruction,
312→        compiledRuleJson: JSON.stringify(rule.compiledRule),
313→        sourceSessionId: rule.sourceSessionId ?? null,
314→        createdAt: rule.createdAt,
315→        updatedAt: rule.updatedAt,
316→      })
317→      .run();
318→
319→    recordAdjustmentEvent(
320→      {
321→        importId: input.importId,
322→        ruleId: rule.id,
323→        sessionId: input.sourceSessionId,
324→        targetFormat: input.targetFormat,
325→        type: "rule_applied",
326→      },
