433→export function reopenAdjustmentSession(sessionId: string) {
434→  const session = getAdjustmentSession(sessionId);
435→
436→  if (!session) {
437→    throw new Error("Anpassungssession nicht gefunden.");
438→  }
439→
440→  db.update(adjustmentSessions)
441→    .set({
442→      status: "open",
443→      previewArtifactJson: null,
444→      updatedAt: now(),
445→    })
446→    .where(eq(adjustmentSessions.id, sessionId))
447→    .run();
448→
449→  const updated = getAdjustmentSession(sessionId);
450→
451→  if (!updated) {
452→    throw new Error("Anpassungssession konnte nicht neu geladen werden.");
453→  }
454→
455→  return updated;
456→}
