458→export function listAdjustmentMessages(sessionId: string) {
459→  return db
460→    .select()
461→    .from(adjustmentMessages)
462→    .where(eq(adjustmentMessages.sessionId, sessionId))
463→    .orderBy(asc(adjustmentMessages.createdAt))
464→    .all()
465→    .map(deserializeAdjustmentMessage);
