478→export function getAdjustmentSessionDetail(
479→  sessionId: string,
480→): AdjustmentSessionDetail | undefined {
481→  const session = getAdjustmentSession(sessionId);
482→
483→  if (!session) {
484→    return undefined;
485→  }
486→
487→  return adjustmentSessionDetailSchema.parse({
488→    messages: listAdjustmentMessages(sessionId),
489→    session,
490→  });
491→}
