 56→function now() {
 57→  return new Date().toISOString();
 58→}
 59→
 60→function parseJson<T>(value: string | null): T | undefined {
 61→  if (!value) {
 62→    return undefined;
 63→  }
 64→
 65→  return JSON.parse(value) as T;
 66→}
