191→function buildSelectorSchema(targetFormat: AdjustmentTargetFormat = "reader") {
192→  const isMarkdown = targetFormat === "markdown";
193→
194→  // For Markdown, compound selectors only support textPattern (line-based matching).
195→  // blockType, messageRole, headingLevel, position, and context are block/message
196→  // concepts that do not exist in the flat line-based Markdown representation and
197→  // are silently ignored by applyMarkdownRules. Exposing them would mislead the AI
198→  // into generating selectors that appear meaningful but have no effect.
199→  const compoundProperties = isMarkdown
200→    ? {
201→        textPattern: {
202→          type: "string",
203→          description:
204→            "Nur für compound: Regex-Pattern das im Markdown-Text matchen muss.",
205→        },
206→      }
207→    : {
208→        messageRole: {
209→          type: "string",
210→          enum: ["user", "assistant", "system", "tool"],
211→          description: "Nur für compound: Nachrichten dieser Rolle matchen.",
212→        },
213→        headingLevel: {
214→          type: "number",
215→          description: "Nur für compound: Überschriften-Ebene 1-6.",
216→        },
217→        position: {
218→          type: "string",
219→          enum: ["first", "last"],
220→          description:
221→            "Nur für compound: Erster oder letzter Block einer Nachricht.",
222→        },
223→        textPattern: {
224→          type: "string",
225→          description:
226→            "Nur für compound: Regex-Pattern das im Block-Text matchen muss.",
227→        },
228→        context: {
229→          type: "object",
230→          description: "Nur für compound: Nachbar-Block-Filter.",
231→          properties: {
232→            previousSibling: {
233→              type: "object",
234→              properties: {
235→                blockType: { type: "string" },
236→                headingLevel: { type: "number" },
237→                textPattern: { type: "string" },
238→              },
239→            },
240→            nextSibling: {
241→              type: "object",
242→              properties: {
243→                blockType: { type: "string" },
244→                headingLevel: { type: "number" },
245→                textPattern: { type: "string" },
246→              },
247→            },
248→          },
249→        },
250→      };
251→
252→  return {
253→    type: "object",
254→    properties: {
255→      strategy: {
256→        type: "string",
257→        enum: [
258→          "exact",
259→          "block_type",
260→          "prefix_before_colon",
261→          "markdown_table",
262→          "compound",
263→        ],
264→        description:
265→          "exact = nur dieser eine Block, block_type = alle Blöcke dieses Typs, compound = flexible Kombination aus Filtern.",
266→      },
267→      messageId: {
268→        type: "string",
269→        description: "ID der Nachricht (aus dem Kontext übernehmen).",
270→      },
271→      ...(targetFormat !== "markdown"
272→        ? {
273→            blockId: {
274→              type: "string",
275→              description: "ID des Blocks (aus dem Kontext übernehmen).",
276→            },
277→          }
278→        : {}),
279→      blockIndex: {
280→        type: "number",
281→        description: "Index des Blocks (aus dem Kontext übernehmen).",
282→      },
283→      blockType: {
284→        type: "string",
285→        enum: ["paragraph", "heading", "list", "quote", "code", "table"],
286→        description: "Typ des Blocks (aus dem Kontext übernehmen).",
287→      },
288→      lineStart: {
289→        type: "number",
290→        description: "Nur für Markdown: erste Zeile.",
291→      },
292→      lineEnd: {
293→        type: "number",
294→        description: "Nur für Markdown: letzte Zeile.",
295→      },
296→      ...compoundProperties,
297→    },
298→    required: ["strategy"],
299→  };
300→}
301→
