573→// ---------------------------------------------------------------------------
574→// OpenAI helpers
575→// ---------------------------------------------------------------------------
576→
577→function isRecord(value: unknown): value is Record<string, unknown> {
578→  return Boolean(value) && typeof value === "object" && !Array.isArray(value);
579→}
580→
581→function extractFunctionCalls(payload: ResponsesPayload): FunctionCallItem[] {
582→  if (!Array.isArray(payload.output)) {
583→    return [];
584→  }
585→
586→  return payload.output.flatMap((item) => {
587→    if (!isRecord(item) || item.type !== "function_call") {
588→      return [];
589→    }
590→
591→    const callId = typeof item.call_id === "string" ? item.call_id : null;
592→    const name = typeof item.name === "string" ? item.name : null;
593→    const args = typeof item.arguments === "string" ? item.arguments : null;
594→
595→    if (!callId || !name || !args) {
596→      return [];
597→    }
598→
599→    return [{ arguments: args, callId, name }];
600→  });
601→}
602→
603→function extractAssistantMessage(payload: ResponsesPayload) {
604→  if (typeof payload.output_text === "string" && payload.output_text.trim()) {
605→    return payload.output_text.trim();
606→  }
607→
608→  if (!Array.isArray(payload.output)) {
609→    return "";
610→  }
611→
612→  return payload.output
613→    .flatMap((item) => {
614→      if (
615→        !isRecord(item) ||
616→        item.type !== "message" ||
617→        item.role !== "assistant"
618→      ) {
619→        return [];
620→      }
621→
622→      const content = item.content;
623→      if (!Array.isArray(content)) {
624→        return [];
625→      }
626→
627→      return content.flatMap((entry) => {
628→        if (!isRecord(entry) || entry.type !== "output_text") {
629→          return [];
630→        }
631→
632→        return typeof entry.text === "string" && entry.text.trim()
633→          ? [entry.text.trim()]
634→          : [];
635→      });
636→    })
637→    .join("\n")
638→    .trim();
639→}
