641→async function requestOpenAiResponse(
642→  body: Record<string, unknown>,
643→  config: ReturnType<typeof readAdjustmentAiConfig>,
644→) {
645→  const response = await fetch(`${config.openai?.apiBaseUrl}/responses`, {
646→    method: "POST",
647→    headers: {
648→      "Content-Type": "application/json",
649→      Authorization: `Bearer ${config.openai?.apiKey}`,
650→    },
651→    body: JSON.stringify({
652→      model: config.model,
653→      reasoning: { effort: "medium" },
654→      store: true,
655→      ...body,
656→    }),
657→    signal: AbortSignal.timeout(config.timeoutMs),
658→  });
659→
660→  if (!response.ok) {
661→    const errorText = await response.text();
662→    throw new AgentUnavailableError(
663→      `Die Live-KI-Antwort war nicht verfügbar (${response.status}). ${errorText.slice(0, 240)}`,
664→    );
665→  }
666→
667→  return (await response.json()) as ResponsesPayload;
668→}
669→
670→// ---------------------------------------------------------------------------
671→// Tool execution with validation
672→// ---------------------------------------------------------------------------
673→
674→function validateEffect(effect: unknown): {
675→  ok: boolean;
676→  data?: Record<string, unknown>;
677→  error?: string;
678→} {
679→  const result = customStyleEffectSchema.safeParse(effect);
680→  if (result.success) {
681→    return { ok: true, data: result.data as Record<string, unknown> };
682→  }
683→
684→  const issues = result.error.issues
685→    .map((i) => `${i.path.join(".")}: ${i.message}`)
686→    .join("; ");
687→  return { ok: false, error: `Effect-Validierung fehlgeschlagen: ${issues}` };
688→}
689→
690→async function executeToolCall(
691→  call: FunctionCallItem,
692→  callbacks: RunAgentTurnInput["callbacks"],
693→  actions: ActionRecord[],
694→): Promise<string> {
695→  let args: Record<string, unknown>;
696→  try {
697→    args = JSON.parse(call.arguments) as Record<string, unknown>;
698→  } catch {
699→    return JSON.stringify({
700→      ok: false,
701→      error: `Ungültige Tool-Argumente: ${call.arguments}`,
702→    });
703→  }
704→
705→  if (call.name === "create_rule") {
706→    const effectValidation = validateEffect(args.effect);
707→    if (!effectValidation.ok) {
708→      return JSON.stringify({ ok: false, error: effectValidation.error });
709→    }
710→
711→    try {
712→      const { ruleId } = await callbacks.onCreateRule({
713→        selector: args.selector as Record<string, unknown>,
714→        effect: effectValidation.data as Record<string, unknown>,
715→        description: String(args.description ?? ""),
716→      });
717→      actions.push({ type: "created", ruleId });
718→      return JSON.stringify({ ok: true, ruleId });
719→    } catch (error) {
720→      return JSON.stringify({
721→        ok: false,
722→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
723→      });
724→    }
725→  }
726→
727→  if (call.name === "update_rule") {
728→    const effectValidation = validateEffect(args.effect);
729→    if (!effectValidation.ok) {
730→      return JSON.stringify({ ok: false, error: effectValidation.error });
731→    }
732→
733→    const ruleId = String(args.ruleId ?? "");
734→
735→    try {
736→      await callbacks.onUpdateRule({
737→        ruleId,
738→        effect: effectValidation.data as Record<string, unknown>,
739→        description:
740→          typeof args.description === "string" ? args.description : undefined,
741→      });
742→      actions.push({ type: "updated", ruleId });
743→      return JSON.stringify({ ok: true, ruleId });
744→    } catch (error) {
745→      return JSON.stringify({
746→        ok: false,
747→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
748→      });
749→    }
750→  }
751→
752→  if (call.name === "delete_rule") {
753→    const ruleId = String(args.ruleId ?? "");
754→
755→    try {
756→      await callbacks.onDeleteRule(ruleId);
757→      actions.push({ type: "deleted", ruleId });
758→      return JSON.stringify({ ok: true, ruleId });
759→    } catch (error) {
760→      return JSON.stringify({
761→        ok: false,
762→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
763→      });
764→    }
765→  }
766→
767→  return JSON.stringify({
768→    ok: false,
769→    error: `Unbekannter Tool-Call: ${call.name}`,
770→  });
771→}
772→
773→// ---------------------------------------------------------------------------
774→// Main agent turn
775→// ---------------------------------------------------------------------------
776→
777→export async function runAgentTurn(input: RunAgentTurnInput): Promise<{
778→  assistantMessage: string;
779→  actions: ActionRecord[];
780→}> {
781→  const config = readAdjustmentAiConfig();
782→
783→  if (!config.enabled || config.provider !== "openai" || !config.openai) {
784→    throw new AgentUnavailableError(
785→      "Live-KI-Anpassungen sind aktuell nicht konfiguriert. Hinterlege einen OpenAI-Zugang, bevor du diesen Chat nutzt.",
786→    );
787→  }
788→
789→  const actions: ActionRecord[] = [];
790→  const targetFormat = input.sessionDetail.session.targetFormat;
791→
792→  const inputMessages = buildInputMessages(input);
793→
794→  let payload = await requestOpenAiResponse(
795→    {
796→      input: inputMessages,
797→      tool_choice: "auto",
798→      tools: buildTools(targetFormat),
799→    },
800→    config,
801→  );
802→
803→  for (let round = 0; round < MAX_TOOL_ROUNDS; round += 1) {
804→    const functionCalls = extractFunctionCalls(payload);
805→    if (functionCalls.length === 0) {
806→      break;
807→    }
808→
809→    if (!payload.id) {
810→      throw new Error(
811→        "Die KI-Antwort enthält keine Response-ID für den Tool-Loop.",
812→      );
813→    }
814→
815→    const toolOutputs = [];
816→
817→    for (const call of functionCalls) {
818→      const result = await executeToolCall(call, input.callbacks, actions);
819→      toolOutputs.push({
820→        type: "function_call_output",
821→        call_id: call.callId,
822→        output: result,
823→      });
824→    }
825→
826→    payload = await requestOpenAiResponse(
827→      {
828→        input: toolOutputs,
829→        previous_response_id: payload.id,
830→        tool_choice: "auto",
831→        tools: buildTools(targetFormat),
832→      },
833→      config,
834→    );
835→  }
836→
837→  const rawMessage = extractAssistantMessage(payload);
838→  let assistantMessage: string;
839→
840→  if (rawMessage) {
841→    assistantMessage = rawMessage;
842→  } else if (actions.length > 0) {
843→    assistantMessage = "Die Änderung ist jetzt sichtbar.";
844→  } else {
845→    // The AI returned no text and took no actions — retry once with an
846→    // explicit nudge so the user sees an actual question instead of a
847→    // generic placeholder.
848→    const retryPayload = await requestOpenAiResponse(
849→      {
850→        input: [
851→          ...inputMessages,
852→          {
853→            content: [
854→              {
855→                text: "Du hast gerade keine Antwort gegeben. Bitte stelle dem Nutzer jetzt eine konkrete Rückfrage, damit du eine passende Regel erstellen kannst.",
856→                type: "input_text",
857→              },
858→            ],
859→            role: "user",
860→          },
861→        ],
862→        tool_choice: "none",
863→        tools: buildTools(targetFormat),
864→      },
865→      config,
866→    );
867→
868→    assistantMessage =
869→      extractAssistantMessage(retryPayload) ||
870→      "Ich konnte die Anfrage nicht verstehen. Kannst du bitte genauer beschreiben, was du ändern möchtest?";
871→  }
872→
873→  return { assistantMessage, actions };
874→}
